import base64
import zipfile
import io

# 你的 Base64 字符串
base64_str = ""

try:
    # 1. Base64 解码
    decoded_bytes = base64.b64decode(base64_str)
    
    # 2. 尝试作为 ZIP 文件打开
    zip_file = zipfile.ZipFile(io.BytesIO(decoded_bytes))
    
    print("✅ Base64 格式正确")
    print("✅ ZIP 结构完整")
    print(f"📄 包含的文件列表:")
    for name in zip_file.namelist():
        print(f"   - {name}")
    with open('./output/test.xlsx', 'wb') as f:
        f.write(decoded_bytes)
    print("文件已保存为 test.xlsx")

        
except Exception as e:
    print(f"❌ 验证失败: {str(e)}")
